SELECT 
  FROM emp.tn_emp_cntry_pair p
 WHERE p.emp_plan_id = #{empPlanId}
   AND p.pair_sn     = #{sn}
   AND NOW() BETWEEN p.use_bgng_dt AND p.use_end_dt

SELECT COALESCE(MAX(pair_sn), 0) + 1
  FROM emp.tn_emp_cntry_pair
 WHERE emp_plan_id = #{empPlanId}

SELECT COUNT(*)
  FROM emp.tn_emp_cntry_pair
 WHERE emp_plan_id    = #{empPlanId}
   AND dprtr_cntry_cd = #{dprtrCntryCd}
   AND arvl_cntry_cd  = #{arvlCntryCd}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

   AND pair_sn != #{excludeSn}

mapper.update:
UPDATE emp.tn_emp_cntry_pair
   SET dprtr_cntry_cd  = #{dprtrCntryCd},
       arvl_cntry_cd   = #{arvlCntryCd},
       intl_yn          = #{intlYn},
       exempt_cd        = #{exemptCd},
       last_chg_dt      = NOW(),
       last_chg_user_id = #{lastChgUserId}
 WHERE emp_plan_id = #{empPlanId}
   AND pair_sn     = #{pairSn}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

UPDATE emp.tn_emp_cntry_pair
   SET use_end_dt       = NOW() - INTERVAL '1 minute',
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE emp_plan_id = #{empPlanId}
   AND pair_sn     = #{sn}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
